        return value;
    }

    /**
     * @dev Escape special characters in JSON strings. This can be useful to prevent JSON injection in NFT metadata.
     *
     * WARNING: This function should only be used in double quoted JSON strings. Single quotes are not escaped.
     *
     * NOTE: This function escapes backslashes (including those in \uXXXX sequences) and the characters in ranges
     * defined in section 2.5 of RFC-4627 (U+0000 to U+001F, U+0022 and U+005C). All control characters in U+0000
     * to U+001F are escaped (\b, \t, \n, \f, \r use short form; others use \u00XX). ECMAScript's `JSON.parse` does
     * recover escaped unicode characters that are not in this range, but other tooling may provide different results.
     */
    function escapeJSON(string memory input) internal pure returns (string memory) {
        bytes memory buffer = bytes(input);

        // Put output at the FMP. Memory will be reserved later when we figure out the actual length of the escaped
        // string. All write are done using _unsafeWriteBytesOffset, which avoid the (expensive) length checks for
        // each character written.
        bytes memory output;
        assembly ("memory-safe") {
            output := mload(0x40)
        }
        uint256 outputLength = 0;

        for (uint256 i = 0; i < buffer.length; ++i) {
            uint8 char = uint8(bytes1(_unsafeReadBytesOffset(buffer, i)));
            if (((SPECIAL_CHARS_LOOKUP & (1 << char)) != 0)) {
                _unsafeWriteBytesOffset(output, outputLength++, "\\");
                if (char == 0x08) _unsafeWriteBytesOffset(output, outputLength++, "b");
                else if (char == 0x09) _unsafeWriteBytesOffset(output, outputLength++, "t");
                else if (char == 0x0a) _unsafeWriteBytesOffset(output, outputLength++, "n");
                else if (char == 0x0c) _unsafeWriteBytesOffset(output, outputLength++, "f");
                else if (char == 0x0d) _unsafeWriteBytesOffset(output, outputLength++, "r");
                else if (char == 0x5c) _unsafeWriteBytesOffset(output, outputLength++, "\\");
                else if (char == 0x22) {
                    // solhint-disable-next-line quotes
                    _unsafeWriteBytesOffset(output, outputLength++, '"');
                } else {
                    // U+0000 to U+001F without short form: output \u00XX
                    _unsafeWriteBytesOffset(output, outputLength++, "u");
                    _unsafeWriteBytesOffset(output, outputLength++, "0");
                    _unsafeWriteBytesOffset(output, outputLength++, "0");
                    _unsafeWriteBytesOffset(output, outputLength++, HEX_DIGITS[char >> 4]);
                    _unsafeWriteBytesOffset(output, outputLength++, HEX_DIGITS[char & 0x0f]);
                }
            } else {
                _unsafeWriteBytesOffset(output, outputLength++, bytes1(char));
            }
        }
        // write the actual length and reserve memory
        assembly ("memory-safe") {
            mstore(output, outputLength)
            mstore(0x40, add(output, add(outputLength, 0x20)))
        }

        return string(output);
    }

    /**
     * @dev Reads a bytes32 from a bytes array without bounds checking.
     *
     * NOTE: making this function internal would mean it could be used with memory unsafe offset, and marking the
     * assembly block as such would prevent some optimizations.
     */
    function _unsafeReadBytesOffset(bytes memory buffer, uint256 offset) private pure returns (bytes32 value) {
        // This is not memory safe in the general case, but all calls to this private function are within bounds.
        assembly ("memory-safe") {
            value := mload(add(add(buffer, 0x20), offset))
        }
    }

    /**
     * @dev Write a bytes1 to a bytes array without bounds checking.
     *
     * NOTE: making this function internal would mean it could be used with memory unsafe offset, and marking the
     * assembly block as such would prevent some optimizations.
     */
    function _unsafeWriteBytesOffset(bytes memory buffer, uint256 offset, bytes1 value) private pure {
        // This is not memory safe in the general case, but all calls to this private function are within bounds.
        assembly ("memory-safe") {
            mstore8(add(add(buffer, 0x20), offset), shr(248, value))
        }
    }
}

contracts/AuditRegistry.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity 0.8.24;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/utils/cryptography/ECDSA.sol";
import "@openzeppelin/contracts/utils/cryptography/MessageHashUtils.sol";

/// @title AuditRegistry — On-Chain Smart Contract Audit Anchoring
/// @notice Append-only registry of audit reports on Avalanche Fuji.
///         Anyone can verify a report by checking reportHash against the IPFS CID.
/// @dev Audit records are permanent — no deletion, no modification.
contract AuditRegistry is Ownable, ReentrancyGuard {

    using ECDSA for bytes32;
    using MessageHashUtils for bytes32;

    // ── Structs ────────────────────────────────────────────────
    struct AuditRecord {
        uint256 auditId;
        address contractAddr;
        bytes32 reportHash;         // keccak256 of full report JSON
        bytes32 merkleRoot;         // Merkle root of findings array
        string  reportCID;          // IPFS CID of full report
        address auditor;            // server signer address
        uint256 timestamp;
        uint256 blockNumber;
        uint256 score;              // 0–100
    }

    // ── State ──────────────────────────────────────────────────
    uint256 private _nextAuditId;

    /// contractAddr → array of audit records (history)
    mapping(address => AuditRecord[]) private _auditHistory;

    /// auditId → (contractAddr, index) for direct lookup
    mapping(uint256 => address) private _auditIdToContract;

    /// Authorised auditor addresses (TrustBox server signers)
    mapping(address => bool) public authorisedAuditors;

    // ── Events ─────────────────────────────────────────────────
    event AuditSubmitted(
        uint256 indexed auditId,
        address indexed contractAddr,
        bytes32         reportHash,
        bytes32         merkleRoot,
        string          reportCID,
        address indexed auditor,
        uint256         score
    );

    event AuditorAdded(address indexed auditor);
    event AuditorRemoved(address indexed auditor);

    // ── Constructor ────────────────────────────────────────────
    constructor() Ownable(msg.sender) {
        // Owner is the first authorised auditor
        authorisedAuditors[msg.sender] = true;
        emit AuditorAdded(msg.sender);
    }

    // ── Auditor management ─────────────────────────────────────

    function addAuditor(address auditor) external onlyOwner {
        authorisedAuditors[auditor] = true;
        emit AuditorAdded(auditor);
    }

    function removeAuditor(address auditor) external onlyOwner {
        authorisedAuditors[auditor] = false;
        emit AuditorRemoved(auditor);
    }

    // ── Core functions ─────────────────────────────────────────

    /// @notice Anchor an audit report. Validates auditor signature.
    /// @param contractAddr  The audited contract address
    /// @param reportHash    keccak256 of the full report JSON
    /// @param merkleRoot    Merkle root of the findings array
    /// @param reportCID     IPFS CID of the full report
    /// @param auditorSig    Server-side signature over reportHash
    /// @param score         Audit score 0–100
    function submitAudit(
        address contractAddr,
        bytes32 reportHash,
        bytes32 merkleRoot,
        string  calldata reportCID,
        bytes   calldata auditorSig,
        uint256 score
    ) external nonReentrant returns (uint256 auditId) {
        require(contractAddr != address(0),    "AuditRegistry: zero contractAddr");
        require(reportHash != bytes32(0),      "AuditRegistry: empty reportHash");
        require(bytes(reportCID).length > 0,   "AuditRegistry: empty reportCID");
        require(score <= 100,                  "AuditRegistry: score out of range");

        // Recover signer from auditorSig
        address signer = reportHash
            .toEthSignedMessageHash()
            .recover(auditorSig);

        require(authorisedAuditors[signer], "AuditRegistry: unauthorised auditor");

        auditId = _nextAuditId++;

        AuditRecord memory record = AuditRecord({
            auditId:     auditId,
            contractAddr:contractAddr,
            reportHash:  reportHash,
            merkleRoot:  merkleRoot,
            reportCID:   reportCID,
            auditor:     signer,
            timestamp:   block.timestamp,
            blockNumber: block.number,
            score:       score
        });

        _auditHistory[contractAddr].push(record);
        _auditIdToContract[auditId] = contractAddr;

        emit AuditSubmitted(auditId, contractAddr, reportHash, merkleRoot, reportCID, signer, score);
    }

    // ── View functions ─────────────────────────────────────────

    /// @notice Get the most recent audit for a contract
    function getAudit(address contractAddr) external view returns (AuditRecord memory) {
        AuditRecord[] storage history = _auditHistory[contractAddr];
        require(history.length > 0, "AuditRegistry: no audit found");
        return history[history.length - 1];
    }

    /// @notice Get full audit history for a contract
    function getAuditHistory(address contractAddr) external view returns (AuditRecord[] memory) {
        return _auditHistory[contractAddr];
    }

    /// @notice Verify a report hash matches any recorded audit
    function verifyReport(address contractAddr, bytes32 reportHash) external view returns (bool) {
        AuditRecord[] storage history = _auditHistory[contractAddr];
        for (uint i = 0; i < history.length; i++) {
            if (history[i].reportHash == reportHash) return true;
        }
        return false;
    }

    /// @notice Total audits submitted
    function totalAudits() external view returns (uint256) {
        return _nextAuditId;
    }
}

contracts/evm/src/AgentMarketPlace.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity 0.8.24;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/token/ERC20/IERC20.sol";
import "@openzeppelin/contracts/token/ERC20/utils/SafeERC20.sol";

/// @title AgentMarketplace — TEE Agent Staking, Registration & Job Dispatch
/// @notice Agents stake AVAX to register. Users dispatch blind audit jobs.
///         Phala TEE agents process jobs off-chain and post results here.
/// @dev Integrates with TrustRegistry for ERC-8004 credential verification.
contract AgentMarketplace is Ownable, ReentrancyGuard {

    using SafeERC20 for IERC20;

    // ── Constants ──────────────────────────────────────────────
    uint256 public constant MIN_STAKE       = 0.1 ether;   // 0.1 AVAX minimum stake
    uint256 public constant JOB_EXPIRY      = 24 hours;
    uint256 public constant DISPUTE_WINDOW  = 48 hours;

    // ── Enums ──────────────────────────────────────────────────
    enum AgentStatus { Inactive, Active, Busy, Slashed }
    enum JobStatus   { Open, Assigned, Completed, Failed, Disputed, Expired }

    // ── Structs ────────────────────────────────────────────────
    struct Agent {
        string      agentId;
        address     operator;
        string      teeEndpoint;        // Phala Phat contract URL
        bytes       encPubKey;          // Encryption public key for blind jobs
        uint256     stake;              // AVAX staked
        uint256     tokenId;            // ERC-8004 token from TrustRegistry (0 = not minted yet)
        uint256     jobsCompleted;
        uint256     jobsFailed;
        uint256     registeredAt;
        AgentStatus status;
    }

    struct Job {
        uint256     jobId;
        address     requester;
        bytes32     agentKey;           // keccak256(agentId, operator)
        bytes       encryptedPayload;   // Encrypted with agent's encPubKey
        bytes32     payloadHash;        // keccak256 of plaintext — for result verification
        string      resultCID;          // IPFS CID of encrypted result
        bytes32     resultHash;         // keccak256 of result
        uint256     fee;                // AVAX fee locked for this job
        uint256     createdAt;
        uint256     completedAt;
        JobStatus   status;
    }

    // ── State ──────────────────────────────────────────────────
    uint256 private _nextJobId;

    /// agentKey → Agent
    mapping(bytes32 => Agent) private _agents;

    /// operator → list of agentKeys
    mapping(address => bytes32[]) private _operatorAgents;

    /// jobId → Job
    mapping(uint256 => Job) private _jobs;

    /// agentKey → list of jobIds
    mapping(bytes32 => uint256[]) private _agentJobs;

    /// requester → list of jobIds
    mapping(address => uint256[]) private _requesterJobs;

    /// Platform fee (basis points, e.g. 200 = 2%)
    uint256 public platformFeeBps = 200;
    uint256 public platformFeeAccrued;

    // ── Events ─────────────────────────────────────────────────
    event AgentRegistered(
        bytes32 indexed agentKey,
        string          agentId,
        address indexed operator,
        string          teeEndpoint,
        uint256         stake
    );

    event AgentStakeUpdated(bytes32 indexed agentKey, uint256 newStake);
    event AgentStatusChanged(bytes32 indexed agentKey, AgentStatus status);

    event JobCreated(
        uint256 indexed jobId,
        address indexed requester,
        bytes32 indexed agentKey,
        uint256         fee
    );

    event JobCompleted(
        uint256 indexed jobId,
        bytes32 indexed agentKey,
        string          resultCID,
        bytes32         resultHash
    );

    event JobFailed(uint256 indexed jobId, bytes32 indexed agentKey);
    event JobDisputed(uint256 indexed jobId, address indexed disputer);
    event AgentSlashed(bytes32 indexed agentKey, uint256 slashedAmount);

    // ── Constructor ────────────────────────────────────────────
    constructor() Ownable(msg.sender) {}

    // ── Agent registration ─────────────────────────────────────

    /// @notice Register a TEE agent with stake
    /// @param agentId      Unique agent identifier (matches TrustRegistry)
    /// @param teeEndpoint  Phala Phat contract URL
    /// @param encPubKey    Encryption public key (65 bytes, uncompressed secp256k1)
    function registerAgent(
        string  calldata agentId,
        string  calldata teeEndpoint,
        bytes   calldata encPubKey
    ) external payable nonReentrant {
        require(bytes(agentId).length > 0,      "Marketplace: empty agentId");
        require(bytes(teeEndpoint).length > 0,  "Marketplace: empty endpoint");
        require(encPubKey.length == 65,         "Marketplace: invalid pubkey");
        require(msg.value >= MIN_STAKE,         "Marketplace: insufficient stake");

        bytes32 key = _agentKey(agentId, msg.sender);
        require(_agents[key].registeredAt == 0, "Marketplace: already registered");

        _agents[key] = Agent({
            agentId:       agentId,
            operator:      msg.sender,
            teeEndpoint:   teeEndpoint,
            encPubKey:     encPubKey,
            stake:         msg.value,
            tokenId:       0,
            jobsCompleted: 0,
            jobsFailed:    0,
            registeredAt:  block.timestamp,
            status:        AgentStatus.Active
        });

        _operatorAgents[msg.sender].push(key);

        emit AgentRegistered(key, agentId, msg.sender, teeEndpoint, msg.value);
    }

    /// @notice Add more stake to an existing agent
    function topUpStake(string calldata agentId) external payable nonReentrant {
        bytes32 key = _agentKey(agentId, msg.sender);
        require(_agents[key].registeredAt > 0, "Marketplace: not registered");
        require(msg.value > 0,                  "Marketplace: zero stake");

        _agents[key].stake += msg.value;
        emit AgentStakeUpdated(key, _agents[key].stake);
    }

    /// @notice Link an ERC-8004 tokenId to this agent after TrustRegistry mint
    function setTokenId(string calldata agentId, uint256 tokenId) external {
        bytes32 key = _agentKey(agentId, msg.sender);
        require(_agents[key].registeredAt > 0,  "Marketplace: not registered");
        require(_agents[key].operator == msg.sender, "Marketplace: not operator");
        _agents[key].tokenId = tokenId;
    }

    // ── Job dispatch ───────────────────────────────────────────

    /// @notice Dispatch a blind audit job to a specific TEE agent
    /// @param agentId          Target agent identifier
    /// @param agentOperator    Target agent's operator address
    /// @param encryptedPayload Payload encrypted with agent's encPubKey
    /// @param payloadHash      keccak256 of plaintext payload (for verification)
    function createJob(
        string  calldata agentId,
        address          agentOperator,
        bytes   calldata encryptedPayload,
        bytes32          payloadHash
    ) external payable nonReentrant returns (uint256 jobId) {
        require(bytes(encryptedPayload).length > 0, "Marketplace: empty payload");
        require(payloadHash != bytes32(0),           "Marketplace: empty payloadHash");
        require(msg.value > 0,                       "Marketplace: fee required");

        bytes32 key = _agentKey(agentId, agentOperator);
        Agent storage agent = _agents[key];
        require(agent.registeredAt > 0,              "Marketplace: agent not found");
        require(agent.status == AgentStatus.Active,  "Marketplace: agent not available");

        jobId = _nextJobId++;

        _jobs[jobId] = Job({
            jobId:            jobId,
            requester:        msg.sender,
            agentKey:         key,
            encryptedPayload: encryptedPayload,
            payloadHash:      payloadHash,
            resultCID:        "",
            resultHash:       bytes32(0),
            fee:              msg.value,
            createdAt:        block.timestamp,
            completedAt:      0,
            status:           JobStatus.Open
        });

        _agentJobs[key].push(jobId);
        _requesterJobs[msg.sender].push(jobId);

        // Mark agent as busy
        agent.status = AgentStatus.Busy;

        emit JobCreated(jobId, msg.sender, key, msg.value);
    }

    /// @notice TEE agent submits result after processing a job
    /// @param jobId      The job being completed
    /// @param resultCID  IPFS CID of encrypted result
    /// @param resultHash keccak256 of result (for verification)
    function submitResult(
        uint256        jobId,
        string calldata resultCID,
        bytes32         resultHash
    ) external nonReentrant {
        Job storage job = _jobs[jobId];
        require(job.createdAt > 0,             "Marketplace: job not found");
        require(job.status == JobStatus.Open || job.status == JobStatus.Assigned,
                                               "Marketplace: job not open");

        Agent storage agent = _agents[job.agentKey];
        require(agent.operator == msg.sender,  "Marketplace: not agent operator");
        require(bytes(resultCID).length > 0,   "Marketplace: empty resultCID");
        require(resultHash != bytes32(0),      "Marketplace: empty resultHash");

        // Check not expired
        if (block.timestamp > job.createdAt + JOB_EXPIRY) {
            job.status = JobStatus.Expired;
            agent.status = AgentStatus.Active;
            agent.jobsFailed++;
            emit JobFailed(jobId, job.agentKey);
            return;
        }

        job.resultCID   = resultCID;
        job.resultHash  = resultHash;
        job.status      = JobStatus.Completed;
        job.completedAt = block.timestamp;

        agent.status = AgentStatus.Active;
        agent.jobsCompleted++;

        // Pay agent (minus platform fee)
        uint256 fee         = job.fee;
        uint256 platformFee = (fee * platformFeeBps) / 10_000;
        uint256 agentPayout = fee - platformFee;

        platformFeeAccrued += platformFee;

        (bool ok, ) = agent.operator.call{value: agentPayout}("");
        require(ok, "Marketplace: payout failed");

        emit JobCompleted(jobId, job.agentKey, resultCID, resultHash);
    }

    /// @notice Requester disputes a completed job within DISPUTE_WINDOW
    function disputeJob(uint256 jobId) external nonReentrant {
        Job storage job = _jobs[jobId];
        require(job.requester == msg.sender,          "Marketplace: not requester");
        require(job.status == JobStatus.Completed,    "Marketplace: not completed");
        require(
            block.timestamp <= job.completedAt + DISPUTE_WINDOW,
            "Marketplace: dispute window closed"
        );

        job.status = JobStatus.Disputed;
        emit JobDisputed(jobId, msg.sender);
    }

    /// @notice Owner resolves a dispute — slash agent or refund requester
    function resolveDispute(uint256 jobId, bool slashAgent) external onlyOwner nonReentrant {
        Job storage job = _jobs[jobId];
        require(job.status == JobStatus.Disputed, "Marketplace: not disputed");

        Agent storage agent = _agents[job.agentKey];

        if (slashAgent) {
            // Slash 10% of agent stake, refund requester
            uint256 slashAmt = agent.stake / 10;
            agent.stake     -= slashAmt;
            agent.status     = AgentStatus.Slashed;
            agent.jobsFailed++;

            (bool ok, ) = job.requester.call{value: job.fee + slashAmt}("");
            require(ok, "Marketplace: refund failed");

            emit AgentSlashed(job.agentKey, slashAmt);
        }

        job.status = JobStatus.Failed;
        emit JobFailed(jobId, job.agentKey);
    }

    // ── Admin ──────────────────────────────────────────────────

    function setPlatformFee(uint256 bps) external onlyOwner {
        require(bps <= 1000, "Marketplace: max 10%");
        platformFeeBps = bps;
    }

    function withdrawPlatformFees() external onlyOwner nonReentrant {
        uint256 amt = platformFeeAccrued;
        platformFeeAccrued = 0;
        (bool ok, ) = owner().call{value: amt}("");
        require(ok, "Marketplace: withdraw failed");
    }

    // ── View functions ─────────────────────────────────────────

    function getAgent(string calldata agentId, address operator)
        external view returns (Agent memory)
    {
        return _agents[_agentKey(agentId, operator)];
    }

    function getJob(uint256 jobId) external view returns (Job memory) {
        require(_jobs[jobId].createdAt > 0, "Marketplace: job not found");
        return _jobs[jobId];
    }

    function getAgentJobs(string calldata agentId, address operator)
        external view returns (uint256[] memory)
    {
        return _agentJobs[_agentKey(agentId, operator)];
    }

    function getRequesterJobs(address requester) external view returns (uint256[] memory) {
        return _requesterJobs[requester];
    }

    function getOperatorAgents(address operator) external view returns (bytes32[] memory) {
        return _operatorAgents[operator];
    }

    function isAgentAvailable(string calldata agentId, address operator)
        external view returns (bool)
    {
        return _agents[_agentKey(agentId, operator)].status == AgentStatus.Active;
    }

    function totalJobs() external view returns (uint256) {
        return _nextJobId;
    }

    // ── Internal ───────────────────────────────────────────────

    function _agentKey(string calldata agentId, address operator)
        internal pure returns (bytes32)
    {
        return keccak256(abi.encodePacked(agentId, operator));
    }

    // Allow contract to receive AVAX
    receive() external payable {}
}

contracts/evm/src/IntentVault.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity 0.8.24;

import "@openzeppelin/contracts/access/Ownable.sol";
import "@openzeppelin/contracts/utils/ReentrancyGuard.sol";
import "@openzeppelin/contracts/utils/cryptography/ECDSA.sol";
import "@openzeppelin/contracts/utils/cryptography/MessageHashUtils.sol";

/// @title IntentVault — Verifiable Intent Storage + Execution
/// @notice Stores user intents on-chain, triggers CRE workflow via log,
///         and records execution results. Acts as the source of truth
///         for all verifiable actions (book travel, DeFi swap, agent tasks).
/// @dev CRE workflow listens to IntentSubmitted event via logTrigger.
///      After execution, CRE calls markExecuted via writeReport → receiver.
contract IntentVault is Ownable, ReentrancyGuard {

    using ECDSA for bytes32;
    using MessageHashUtils for bytes32;

    // ── Enums ──────────────────────────────────────────────────
    enum IntentStatus { Pending, Executing, Executed, Failed, Cancelled }

    // ── Structs ────────────────────────────────────────────────
    struct Intent {
        bytes32     intentId;
        address     submitter;
        string      spec;           // JSON: { action, entity, params }
        IntentStatus status;
        string      resultCID;      // IPFS CID of execution result
        bool        success;
        uint256     submittedAt;
        uint256     executedAt;
        uint256     nonce;
    }

    // ── State ──────────────────────────────────────────────────
    /// intentId → Intent
    mapping(bytes32 => Intent) private _intents;

    /// submitter → list of intentIds
    mapping(address => bytes32[]) private _userIntents;

    /// submitter → nonce (replay protection)
    mapping(address => uint256) public nonces;

    /// Authorised executors (CRE workflow receiver address)
    mapping(address => bool) public authorisedExecutors;

    // ── Events ─────────────────────────────────────────────────
    /// @notice Emitted when a new intent is submitted — triggers CRE logTrigger
    event IntentSubmitted(
        bytes32 indexed intentId,
        address indexed submitter,
        string          spec,
        uint256         timestamp
    );

    /// @notice Emitted when CRE marks an intent as executed
    event IntentExecuted(
        bytes32 indexed intentId,
        bool            success,
        string          resultCID,
        uint256         timestamp
    );

    event IntentCancelled(bytes32 indexed intentId);
    event ExecutorAdded(address indexed executor);
    event ExecutorRemoved(address indexed executor);

    // ── Constructor ────────────────────────────────────────────
    constructor() Ownable(msg.sender) {
        authorisedExecutors[msg.sender] = true;
    }

    // ── Executor management ────────────────────────────────────

    function addExecutor(address executor) external onlyOwner {
        authorisedExecutors[executor] = true;
        emit ExecutorAdded(executor);
    }

    function removeExecutor(address executor) external onlyOwner {
        authorisedExecutors[executor] = false;
        emit ExecutorRemoved(executor);
    }

    // ── Core functions ─────────────────────────────────────────

    /// @notice Submit a new intent — emits IntentSubmitted to trigger CRE workflow
    /// @param spec      JSON string: { "action": "book_travel", "entity": "...", "params": {...} }
    /// @param signature ECDSA signature over keccak256(spec + nonce) for auth
    /// @return intentId Unique identifier for this intent
    function submitIntent(
        string   calldata spec,
        bytes    calldata signature
    ) external nonReentrant returns (bytes32 intentId) {
        require(bytes(spec).length > 0,      "IntentVault: empty spec");
        require(bytes(spec).length <= 4096,  "IntentVault: spec too long");

        // Verify signature
        uint256 nonce = nonces[msg.sender];
        bytes32 msgHash = keccak256(abi.encodePacked(msg.sender, spec, nonce));
        address signer  = msgHash.toEthSignedMessageHash().recover(signature);
        require(signer == msg.sender, "IntentVault: invalid signature");

        // Generate deterministic intentId
        intentId = keccak256(abi.encodePacked(msg.sender, spec, nonce, block.timestamp));

        require(_intents[intentId].submittedAt == 0, "IntentVault: duplicate intent");

        nonces[msg.sender]++;

        _intents[intentId] = Intent({
            intentId:    intentId,
            submitter:   msg.sender,
            spec:        spec,
            status:      IntentStatus.Pending,
            resultCID:   "",
            success:     false,
            submittedAt: block.timestamp,
            executedAt:  0,
            nonce:       nonce
        });

        _userIntents[msg.sender].push(intentId);

        emit IntentSubmitted(intentId, msg.sender, spec, block.timestamp);
    }

    /// @notice Called by CRE workflow (via writeReport receiver) after execution
    /// @param intentId  The intent being resolved
    /// @param success   Whether execution succeeded
    /// @param resultCID IPFS CID of full execution result
    function markExecuted(
        bytes32        intentId,
        bool           success,
        string calldata resultCID
    ) external nonReentrant {
        require(authorisedExecutors[msg.sender], "IntentVault: unauthorised executor");
        require(bytes(resultCID).length > 0,     "IntentVault: empty resultCID");

        Intent storage intent = _intents[intentId];
        require(intent.submittedAt > 0,          "IntentVault: intent not found");
        require(
            intent.status == IntentStatus.Pending ||
            intent.status == IntentStatus.Executing,
            "IntentVault: intent not pending"
        );

        intent.status    = success ? IntentStatus.Executed : IntentStatus.Failed;
        intent.success   = success;
        intent.resultCID = resultCID;
        intent.executedAt = block.timestamp;

        emit IntentExecuted(intentId, success, resultCID, block.timestamp);
    }

    /// @notice Cancel a pending intent (submitter only)
    function cancelIntent(bytes32 intentId) external nonReentrant {
        Intent storage intent = _intents[intentId];
        require(intent.submitter == msg.sender,       "IntentVault: not submitter");
        require(intent.status == IntentStatus.Pending, "IntentVault: not pending");

        intent.status = IntentStatus.Cancelled;
        emit IntentCancelled(intentId);
    }

    // ── View functions ─────────────────────────────────────────

    function getIntent(bytes32 intentId) external view returns (Intent memory) {
        require(_intents[intentId].submittedAt > 0, "IntentVault: not found");
        return _intents[intentId];
    }

    function getUserIntents(address user) external view returns (bytes32[] memory) {
        return _userIntents[user];
    }

    function getIntentStatus(bytes32 intentId) external view returns (IntentStatus) {
        return _intents[intentId].status;
    }
}

